import request from '@/utils/request'

export const user = {
  // 获取用户信息
  getUserInfo: () => {
    return request({
      url: '/api/v1/users/info/',
      method: 'get'
    })
  },

  // 修改密码
  changePassword: (data) => {
    return request({
      url: '/api/v1/users/password/',
      method: 'put',
      data
    })
  }
}

// 确保导出 changePassword
export const { getUserInfo, changePassword } = user
